class FooEnum {
  public:
    enum class Value {
      kFoo,
      kBaz,
      kBar,
      kOne,
      kZero,
      kUnknown,
    };

    FooEnum() = default;
    FooEnum(Value value) : value_(value) {}  // NOLINT(*-explicit-*)

    /// Unknown wire values are preserved and reported as Value::kUnknown.
    static FooEnum FromString(std::string_view text) {
      if (text == "Foo") return FooEnum(Value::kFoo);
      if (text == "Baz") return FooEnum(Value::kBaz);
      if (text == "Bar") return FooEnum(Value::kBar);
      if (text == "1") return FooEnum(Value::kOne);
      if (text == "0") return FooEnum(Value::kZero);
      FooEnum result;
      result.unknown_ = std::string(text);
      return result;
    }

    Value value() const { return value_; }

    /// Implicit so `switch (x)` works without .value(); the Value equality
    /// overload below keeps comparisons unambiguous despite the conversion.
    operator Value() const { return value_; }  // NOLINT(*-explicit-*)

    /// The wire text, including the original text of unknown values.
    std::string_view ToString() const {
      switch (value_) {
        case Value::kFoo: return "Foo";
        case Value::kBaz: return "Baz";
        case Value::kBar: return "Bar";
        case Value::kOne: return "1";
        case Value::kZero: return "0";
        case Value::kUnknown: return unknown_;
      }
      return unknown_;
    }

    /// Debug rendering for logs and tests — for humans, never parse it.
    void AppendDebugTo(std::string& out) const {
      out += "FooEnum(";
      out += ToString();
      out += ')';
    }
    std::string DebugString() const { std::string out; AppendDebugTo(out); return out; }
    friend std::ostream& operator<<(std::ostream& os, const FooEnum& value) {
      return os << value.DebugString();
    }

    friend bool operator==(const FooEnum&, const FooEnum&) = default;
    friend bool operator==(const FooEnum& a, Value b) { return a.value_ == b; }
    friend auto operator<=>(const FooEnum&, const FooEnum&) = default;
    friend struct std::hash<FooEnum>;

  private:
    Value value_ = Value::kUnknown;
    std::string unknown_;
};


